vm.startPrank(owner);
contractDelegates = new MockContractDelegates(alice, bob, aliceDelegate, bobDelegate);
uint256[] memory tokenIds = new uint256[](3);
tokenIds[0] = 1;
tokenIds[1] = 2;
tokenIds[2] = 3;
VotingDelegationLib.Checkpoint memory checkpoint =
